const n="https://your-app.vercel.app/api";chrome.runtime.onInstalled.addListener(()=>{console.log("Lector AI installed"),chrome.contextMenus.create({id:"summarize-selection",title:"Summarize with Lector AI",contexts:["selection"]}),chrome.contextMenus.create({id:"translate-selection",title:"Translate with Lector AI",contexts:["selection"]})});chrome.contextMenus.onClicked.addListener(e=>{e.menuItemId==="summarize-selection"&&e.selectionText&&o(e.selectionText).then(t=>{chrome.runtime.sendMessage({action:"summary-result",...t}).catch(()=>{})}),e.menuItemId==="translate-selection"&&e.selectionText&&s(e.selectionText).then(t=>{chrome.runtime.sendMessage({action:"translate-result",...t}).catch(()=>{})})});chrome.runtime.onMessage.addListener((e,t,r)=>e.action==="summarize"?(o(e.text).then(r),!0):e.action==="translate"?(s(e.text,e.targetLang).then(r),!0):!1);async function o(e){try{const t=await fetch(`${n}/summarize`,{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({text:e})});if(!t.ok)throw new Error(`HTTP error! status: ${t.status}`);return await t.json()}catch(t){return console.error("Summarize error:",t),{error:"Failed to summarize"}}}async function s(e,t="en"){try{const r=await fetch(`${n}/translate`,{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({text:e,targetLang:t})});if(!r.ok)throw new Error(`HTTP error! status: ${r.status}`);return await r.json()}catch(r){return console.error("Translate error:",r),{error:"Failed to translate"}}}
